38	const itemsBaseSum = (items: Item[]): number => {
39	  let mainBase = 0;
40	  const componentCounts = new Map<string, number>();
41	  for (const item of items) {
42	    const type = item.type as string;
43	    if (COMPONENT_TYPES.has(type)) {
44	      componentCounts.set(type, (componentCounts.get(type) ?? 0) + 1);
45	    } else {
46	      mainBase += itemBasePremium(item);
47	    }
48	  }
49	  let componentBase = 0;
50	  for (const [type, count] of componentCounts) {
51	    componentBase += componentGroupBase(count, BASE_PREMIUM_BY_TYPE[type] ?? 0);
52	  }
53	  return mainBase + componentBase;
54	};
55	
56	const quotePremium = (items: Item[]): number => {
57	  const baseSum = itemsBaseSum(items);
58	  const firstInsuranceSurcharge = baseSum * FIRST_INSURANCE_SURCHARGE_RATE;
59	  return baseSum + firstInsuranceSurcharge + PROCESSING_FEE;
60	};
