62	export const runScenario = (scenario: Scenario): ScenarioResult => {
63	  const results = scenario.steps.map((step) => {
64	    if (step.op === "quote") {
65	      return { premium: quotePremium(step.items) };
66	    }
67	    return { payout: 0, remainingCap: 0 };
68	  });
69	  return { results };
70	};
